// src/ManageOfficers.js
import React from 'react';
import './manageOfficers.css';

const ManageOfficers = () => {
  const officers = [
    { id: 1, name: "John Doe", position: "Manager", email: "john@example.com", phone: "123-456-7890" },
    { id: 2, name: "Jane Smith", position: "Officer", email: "jane@example.com", phone: "123-456-7891" },
    { id: 3, name: "Alice Johnson", position: "Coordinator", email: "alice@example.com", phone: "123-456-7892" },
    { id: 4, name: "Bob Brown", position: "Officer", email: "bob@example.com", phone: "123-456-7893" },
    { id: 5, name: "Charlie Davis", position: "Assistant", email: "charlie@example.com", phone: "123-456-7894" },
    // Add more officers as needed
  ];

  return (
    <div className="manage-officers">
      <h2>Manage Officers</h2>
      <table className="officers-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Position</th>
            <th>Email</th>
            <th>Phone</th>
          </tr>
        </thead>
        <tbody>
          {officers.map(officer => (
            <tr key={officer.id}>
              <td>{officer.id}</td>
              <td>{officer.name}</td>
              <td>{officer.position}</td>
              <td>{officer.email}</td>
              <td>{officer.phone}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ManageOfficers;
